"""

    The parameterless method named isalnum() check if the string containing 
    only digits or alpabetical characters (letter), and returns True or -
    False according to the result

""" 

# Demonstrating the isalnum() method:
print('lambda30'.isalnum())
print('lambda'.isalnum())
print('30'.isalnum())
print('@'.isalnum())
print('lambda_30'.isalnum())
print(''.isalnum())
